func TestValidateOverdueActionRule(t *testing.T) {
	tests := []struct {
		name           string
		afterDays      pgtype.Int4
		action         dbgen.NullOverdueAction
		statusName     pgtype.Text
		recurrenceType dbgen.RecurrenceType
		hasDue         bool
		wantErr        bool
		errContains    string
	}{
		// ─── No rule always passes ───────────────────────────────────────────────────
		{
			name:           "nil rule always valid",
			action:         dbgen.NullOverdueAction{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         false,
			wantErr:        false,
		},

		// ─── advance_recurrence ─────────────────────────────────────────────────────
		{
			name:           "advance_recurrence on one_off is invalid",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        true,
			errContains:    "advance_recurrence is only valid on recurring tasks",
		},
		{
			name:           "advance_recurrence on on_dependency is invalid",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        true,
			errContains:    "advance_recurrence is only valid on recurring tasks",
		},
		{
			name:           "advance_recurrence on fixed_accumulating is invalid",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeFixedAccumulating,
			hasDue:         true,
			wantErr:        true,
			errContains:    "not supported on fixed_accumulating",
		},
		{
			name:           "advance_recurrence on completion_based is valid",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "advance_recurrence on fixed_non_accumulating is valid",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeFixedNonAccumulating,
			hasDue:         true,
			wantErr:        false,
		},

		// ─── set_status ──────────────────────────────────────────────────────────────
		{
			name:           "set_status on one_off is valid with status",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "archived", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "set_status on one_off without status is invalid",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        true,
			errContains:    "status is required",
		},
		{
			name:           "set_status on on_dependency is valid with status",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "blocked", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "set_status on on_dependency without status is invalid",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        true,
			errContains:    "status is required",
		},
		{
			name:           "set_status on completion_based is valid with status",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "done", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "set_status on fixed_non_accumulating is valid with status",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "done", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeFixedNonAccumulating,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "set_status on fixed_accumulating is valid with status",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "done", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeFixedAccumulating,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "set_status without status is invalid",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        true,
			errContains:    "status is required",
		},

		// ─── clear_due_date ─────────────────────────────────────────────────────────
		{
			name:           "clear_due_date on one_off is valid",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "clear_due_date on on_dependency is valid",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "clear_due_date on completion_based is valid",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "clear_due_date on fixed_non_accumulating is valid",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeFixedNonAccumulating,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "clear_due_date on fixed_accumulating is valid",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeFixedAccumulating,
			hasDue:         true,
			wantErr:        false,
		},

		// ─── due date required (all actions, all types) ──────────────────────────────
		{
			name:           "advance_recurrence without due date is invalid",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         false,
			wantErr:        true,
			errContains:    "requires a due date",
		},
		{
			name:           "set_status without due date is invalid",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "done", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         false,
			wantErr:        true,
			errContains:    "requires a due date",
		},
		{
			name:           "clear_due_date without due date is invalid",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         false,
			wantErr:        true,
			errContains:    "requires a due date",
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			err := ValidateOverdueActionRule(tc.afterDays, tc.action, tc.statusName, tc.recurrenceType, tc.hasDue)
			if tc.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				if tc.errContains != "" && !strings.Contains(err.Error(), tc.errContains) {
					t.Errorf("error %q does not contain %q", err.Error(), tc.errContains)
				}
			} else if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
		})
	}
}

